svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var chartArea = svgEl.querySelector('#chart-area');
    var tip = svgEl.querySelector('#tip');
    var tipBg = svgEl.querySelector('#tip-bg');
    var tipBdr = svgEl.querySelector('#tip-bdr');
    var tipTail = svgEl.querySelector('#tip-tail');
    var tipVal = svgEl.querySelector('#tip-val');
    var tipLbl = svgEl.querySelector('#tip-lbl');
    var plotL = 42, plotR = 840, plotT = 100, plotB = 500;
    var meta = {
      bw1: { label:'Cyan', value:'$72M', share:'38%' },
      bw2: { label:'Emerald', value:'$68M', share:'22%' },
      bw3: { label:'Amber', value:'$60M', share:'44%' },
      bw4: { label:'Rose', value:'$55M', share:'15%' },
      bw5: { label:'Violet', value:'$79M', share:'31%' },
      bw6: { label:'Blue', value:'$64M', share:'27%' },
      bw7: { label:'Teal', value:'$61M', share:'42%' },
      bw8: { label:'Other', value:'$48M', share:'12%' }
    };

    function easeInOutCubic(t) {
      return t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;
    }

    function showTip(itemEl) {
      var circle = itemEl.querySelector('circle');
      var m = meta[itemEl.id];
      if (!circle || !m) return;
      var x = parseFloat(circle.getAttribute('cx'));
      var y = parseFloat(circle.getAttribute('cy'));
      var r = parseFloat(circle.getAttribute('r'));
      ctx.layoutSideTooltip(tip, {
        anchorX: x,
        anchorY: y,
        anchorInset: r,
        plotL: plotL,
        plotR: plotR,
        plotT: plotT,
        plotB: plotB,
        lines: [
          { text: m.value, className: 'tip-value' },
          { text: m.label + ' - ' + m.share + ' share', className: 'tip-label' }
        ],
        lineHeights: [70, 62],
        minWidth: 236,
        paddingX: 20,
        paddingY: 24
      });
      ctx.setOpacity(tip, 1);
    }

    function hideTip() { ctx.setOpacity(tip, null); }

    var FADE_DUR = 800, STAGGER = 250;
    var bubGrps = [1,2,3,4,5,6,7,8].map(function (i) {
      return svgEl.querySelector('#bg' + i);
    });

    var startTime = null;
    function animBubbles(ts) {
      if (!startTime) startTime = ts;
      var elapsed = ts - startTime;
      var done = true;
      bubGrps.forEach(function (g, i) {
        var t = Math.max(0, Math.min(1, (elapsed - i * STAGGER) / FADE_DUR));
        g.style.opacity = easeInOutCubic(t).toFixed(3);
        if (t < 1) done = false;
      });
      if (!done) {
        requestAnimationFrame(animBubbles);
      } else {
        bubGrps.forEach(function (g) { g.style.opacity = '1'; });
        chartArea.classList.add('ready');
      }
    }
    requestAnimationFrame(animBubbles);

    var dataItemEls = ctx.$$all('.data-item');
    dataItemEls.forEach(function (itemEl) {
      itemEl.addEventListener('mouseenter', function () {
        chartArea.classList.add('hovering');
        ctx.activateExclusive(dataItemEls, itemEl);
        showTip(itemEl);
      });
      itemEl.addEventListener('mouseleave', function () {
        itemEl.classList.remove('active');
        chartArea.classList.remove('hovering');
        hideTip();
      });
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
